// ============================================================
// Dartboard UI — Steel Darts Pro
// Canvas-based dartboard for 3-dart score input
// ============================================================

var _db = {
  canvas: null,
  darts: [],      // [{score, label, _tapX, _tapY}, ...]  max 3
  open: false,
  mode: 'cu'      // 'cu' = CountUp, '01' = 01 game
};

// Numbers clockwise from top
var DB_NUMS = [20,1,18,4,13,6,10,15,2,17,3,19,7,16,8,11,14,9,12,5];
var DB_SEG  = Math.PI * 2 / 20;
var DB_START = -Math.PI/2 - DB_SEG/2;

// Normalized radii (0–1, where 1.0 = outer edge of double)
// Touch-optimized: inner single drastically shrunk so triple/double
// become finger-friendly tap targets (triple: ×5 wider, double: ×3 wider)
var DB_R = {
  bull:  0.070,  // Bull          (was 0.047)
  obull: 0.160,  // Outer Bull    (was 0.110)
  isin:  0.440,  // inner single outer edge (= obull + 0.280)
  triI:  0.440,  // triple inner edge = isin (no gap)
  triO:  0.590,  // triple outer edge (= triI + 0.150)
  osin:  0.870,  // outer single outer edge — wider (double is checkout-only so thinner)
  dbl:   1.000   // double outer edge (unchanged)
};

// Colors
var DB_C = {
  black: '#1c1a14', cream: '#c8b888',
  red:   '#c0392b', green: '#1a8a3a',
  bull:  '#c0392b', obull: '#1a8a3a',
  wire:  '#a09878', bg:    '#0f0e0a',
  num:   '#e8ff47'
};

// Dart marker colors (dart 1 / 2 / 3)
var DB_DART_COLORS = ['#e8ff47', '#ff9f43', '#ff6b6b'];

// ============================================================
// DRAWING
// ============================================================

function _dbArc(ctx, cx, cy, r1, r2, a1, a2, color) {
  ctx.beginPath();
  ctx.arc(cx, cy, r2, a1, a2, false);
  ctx.arc(cx, cy, r1, a2, a1, true);
  ctx.closePath();
  ctx.fillStyle = color;
  ctx.fill();
}

function dbDraw() {
  var canvas = _db.canvas;
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  var W = canvas.width;
  var CX = W / 2, CY = W / 2;
  var R = W / 2 * 0.84;          // board radius — matches hit test
  var wire = Math.max(1, W / 400);

  ctx.clearRect(0, 0, W, W);

  // Board background
  ctx.fillStyle = DB_C.bg;
  ctx.fillRect(0, 0, W, W);

  // Outer wire ring (gold border)
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.dbl * R + wire * 3, 0, Math.PI * 2);
  ctx.fillStyle = DB_C.wire;
  ctx.fill();

  // Segments: inner single → triple → outer single → double
  for (var i = 0; i < 20; i++) {
    var a1 = DB_START + i * DB_SEG;
    var a2 = a1 + DB_SEG;
    var odd = (i % 2 === 0);
    _dbArc(ctx, CX, CY, DB_R.obull*R, DB_R.isin*R, a1, a2, odd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, DB_R.triI*R,  DB_R.triO*R, a1, a2, odd ? DB_C.red   : DB_C.green);
    _dbArc(ctx, CX, CY, DB_R.triO*R,  DB_R.osin*R, a1, a2, odd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, DB_R.osin*R,  DB_R.dbl*R,  a1, a2, odd ? DB_C.red   : DB_C.green);
  }

  // Radial wire lines
  ctx.strokeStyle = DB_C.wire;
  ctx.lineWidth = wire;
  for (var k = 0; k < 20; k++) {
    var wa = DB_START + k * DB_SEG;
    ctx.beginPath();
    ctx.moveTo(CX + Math.cos(wa) * DB_R.obull * R, CY + Math.sin(wa) * DB_R.obull * R);
    ctx.lineTo(CX + Math.cos(wa) * DB_R.dbl   * R, CY + Math.sin(wa) * DB_R.dbl   * R);
    ctx.stroke();
  }

  // Ring wires
  [DB_R.isin, DB_R.triI, DB_R.triO, DB_R.osin, DB_R.dbl].forEach(function(r) {
    ctx.beginPath();
    ctx.arc(CX, CY, r * R, 0, Math.PI * 2);
    ctx.strokeStyle = DB_C.wire;
    ctx.lineWidth = wire;
    ctx.stroke();
  });

  // Outer bull (green)
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.obull * R, 0, Math.PI * 2);
  ctx.fillStyle = DB_C.obull;
  ctx.fill();
  ctx.strokeStyle = DB_C.wire;
  ctx.lineWidth = wire;
  ctx.stroke();

  // Bull (red)
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.bull * R, 0, Math.PI * 2);
  ctx.fillStyle = DB_C.bull;
  ctx.fill();

  // Number labels — outside the double ring
  var numR = DB_R.dbl * R + wire * 7 + R * 0.055;
  var fontSize = Math.max(10, Math.floor(R * 0.108));
  ctx.font = 'bold ' + fontSize + 'px "Bebas Neue", Arial, sans-serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  for (var j = 0; j < 20; j++) {
    var ca = DB_START + j * DB_SEG + DB_SEG / 2;
    // Alternate color for readability on red/green bands
    ctx.fillStyle = DB_C.num;
    ctx.fillText(String(DB_NUMS[j]),
      CX + Math.cos(ca) * numR,
      CY + Math.sin(ca) * numR);
  }
}

// ============================================================
// DART MARKERS — colored dot where each dart landed
// ============================================================

function _dbDrawMarkers() {
  var canvas = _db.canvas;
  if (!canvas || !_db.darts.length) return;
  var ctx = canvas.getContext('2d');
  var W = canvas.width;
  var H = canvas.height;
  var rect = canvas.getBoundingClientRect();
  var scaleX = W / rect.width;
  var scaleY = H / rect.height;
  var dotR = Math.max(7, Math.min(W, H) * 0.026);

  _db.darts.forEach(function(d, i) {
    if (d._tapX === undefined) return;  // Miss (no tap coord)
    if (d._uiMode && d._uiMode !== _dbUIMode) return;  // hide markers from other UI mode
    if (d._kzZone && d._kzZone !== _dbKzMode) return;  // hide markers from other zone
    var cx = (d._tapX - rect.left) * scaleX;
    var cy = (d._tapY - rect.top)  * scaleY;

    // Drop shadow
    ctx.shadowColor = 'rgba(0,0,0,0.7)';
    ctx.shadowBlur  = W * 0.015;

    // Colored dot
    ctx.beginPath();
    ctx.arc(cx, cy, dotR, 0, Math.PI * 2);
    ctx.fillStyle = DB_DART_COLORS[i];
    ctx.fill();

    ctx.shadowBlur = 0;

    // White outline
    ctx.strokeStyle = 'rgba(255,255,255,0.9)';
    ctx.lineWidth = Math.max(1.5, W * 0.004);
    ctx.stroke();

    // Dart number (1/2/3)
    var fs = Math.max(9, Math.floor(dotR * 1.05));
    ctx.font = 'bold ' + fs + 'px Arial, sans-serif';
    ctx.fillStyle = '#111';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(String(i + 1), cx, cy);
  });
}

// Redraw board (board or kezuri or super zoom) then overlay dart markers
function _dbRedraw() {
  var canvas = _db.canvas;
  if (canvas) {
    var baseSize = Math.round(_dbInitSize * _dbDPR);
    // Always restore canvas to base square size before computing target
    if (canvas.width !== baseSize || canvas.height !== baseSize) {
      if (_dbUIMode !== 'sz') {
        canvas.width  = baseSize;
        canvas.height = baseSize;
        canvas.style.width  = _dbInitSize + 'px';
        canvas.style.height = _dbInitSize + 'px';
        _szLayout = null;
      }
    }
    var H = baseSize;
    var targetW = (_dbUIMode === 'kz') ? Math.round(H * 4 / 3) : H;
    if (canvas.width !== targetW) canvas.width = targetW;
    canvas.style.borderRadius = (_dbUIMode === 'board' || _dbUIMode === 'sz') ? '50%' : '12px';
    canvas.classList.remove('sz-active');  // new SZ is circular — no wide canvas
    var isec = document.getElementById('isec');
    if (isec) isec.classList.toggle('kz-mode', _dbUIMode !== 'board');
  }
  if (_dbUIMode === 'kz')      _dbDrawKezuri();
  else if (_dbUIMode === 'sz') _dbDrawSZ();
  else                          dbDraw();
  _dbDrawMarkers();
}

// ============================================================
// HIT TEST — tap (x,y) → {score, label}
// ============================================================

function _dbHitTest(tapX, tapY) {
  var canvas = _db.canvas;
  var rect = canvas.getBoundingClientRect();
  var CX = rect.left + rect.width  / 2;
  var CY = rect.top  + rect.height / 2;
  var R  = rect.width / 2 * 0.84;  // must match dbDraw()

  var dx = tapX - CX;
  var dy = tapY - CY;
  var r  = Math.sqrt(dx * dx + dy * dy);
  var rn = r / R;

  if (rn < DB_R.bull)  return { score: 50, label: 'Bull' };
  if (rn < DB_R.obull) return { score: 25, label: '25'   };
  if (rn > DB_R.dbl)   return { score: 0,  label: 'Miss' };

  var angle = Math.atan2(dy, dx) * 180 / Math.PI + 90;
  if (angle < 0) angle += 360;
  var segIdx = Math.floor(((angle + 9) % 360) / 18) % 20;
  var num = DB_NUMS[segIdx];

  if (rn < DB_R.isin) return { score: num,    label: String(num) };
  if (rn < DB_R.triO) return { score: num * 3, label: 'T' + num  };
  if (rn < DB_R.osin) return { score: num,    label: String(num) };
  return                     { score: num * 2, label: 'D' + num   };
}

// ============================================================
// DART INPUT LOGIC
// ============================================================

function _dbUpdateDisplay() {
  var totalEl  = document.getElementById('db-total');
  var dartsEl  = document.getElementById('db-darts-disp');
  var countEl  = document.getElementById('db-count-disp');
  var okBtn    = document.getElementById('db-ok-btn');
  var undoBtn  = document.getElementById('db-undo-btn');
  var missBtn  = document.getElementById('db-miss-btn');

  var total = _db.darts.reduce(function(s, d) { return s + d.score; }, 0);
  var n = _db.darts.length;

  if (totalEl) totalEl.textContent = total;
  if (dartsEl) {
    if (n) {
      dartsEl.innerHTML = _db.darts.map(function(d) {
        return '<span class="db-dart-chip">' + d.label + '</span>';
      }).join('');
    } else {
      dartsEl.innerHTML = '<span class="db-dart-empty">—</span>';
    }
  }
  if (countEl) countEl.textContent = ['1本目', '2本目', '3本目', '確認'][Math.min(n, 3)];
  if (okBtn)   okBtn.disabled   = (n === 0);
  if (undoBtn) undoBtn.disabled = (n === 0);
  if (missBtn) missBtn.disabled = (n >= 3);

  // Progress dots
  for (var i = 0; i < 3; i++) {
    var dot = document.getElementById('db-dot-' + i);
    if (dot) dot.className = 'db-dot' + (i < n ? ' db-dot-hit' : '');
  }
}

function _dbAddDart(hit) {
  if (_db.darts.length >= 3) return;
  _db.darts.push(hit);
  _dbUpdateDisplay();
  _dbFlash(hit);
  _dbDrawMarkers();

  // Auto-submit after 3rd dart (only when AUTO is ON)
  if (_db.darts.length === 3 && _dbAutoChange) {
    setTimeout(function() { dbSubmit(); }, 1500);
  }
}

function dbUndoLast() {
  if (_db.darts.length === 0) return;
  _db.darts.pop();
  _dbUpdateDisplay();
  _dbRedraw();  // board + remaining markers
}

function dbAddMiss() {
  if (_db.darts.length >= 3) return;
  _dbAddDart({ score: 0, label: 'Miss' });  // no _tapX/_tapY → no dot drawn
}

// ============================================================
// SUBMIT
// ============================================================

function dbSubmit() {
  var total = _db.darts.reduce(function(s, d) { return s + d.score; }, 0);
  var wasCuPersist = _dbCuPersist && (_db.mode === 'cu');
  dbClose();

  if (_db.mode === '01') {
    if (typeof z01Pre === 'function') z01Pre(total);
    else if (typeof _z01BufUpdate === 'function') {
      _z01BufUpdate(String(total));
      if (typeof z01Ok === 'function') z01Ok();
    }
  } else {
    if (total > 180) total = 180;
    if (typeof commit === 'function') {
      if (typeof buf !== 'undefined') buf = '';
      commit(total);
    }
  }

  // Stay in board mode for CountUp if user didn't explicitly switch to numpad
  if (wasCuPersist) {
    setTimeout(function() {
      var ngp = document.getElementById('ngp');
      var gameOver = ngp && ngp.classList.contains('show');
      if (!gameOver) dbOpen('cu');
    }, 80);
  }
}

// Close board and return to numpad (clears persist preference)
function dbCloseToKey() {
  _dbCuPersist = false;
  dbClose();
}

// ============================================================
// KEZURI MODE (削りモード)
// Zoomed arc view: target segment large + full color,
// adjacent misses visible, everything else grayed out.
// ============================================================

var _dbUIMode    = 'grid';   // 'grid' | 'scr' | 'board' | 'kz' | 'sz'
var _dbKzMode    = 'kz1';   // 'kz1' = T20/T18 zone, 'kz2' = T19/T17 zone
var _dbAutoChange = true;   // auto-submit after 3 darts / auto-switch kz zone (default ON)
var _dbIsInline  = false;   // true when board is shown inline inside #isec
var _dbCuPersist = false;   // true = stay in board mode after each round submit
var _dbDPR       = 1;       // device pixel ratio (set at init)
var _dbInitSize  = 400;     // display size at init in px (set at init)
var _szLayout    = null;    // super zoom section layout for hit test

// Zone definitions
// centerIdx: DB_NUMS index of the segment placed at top-center after rotation
// scoring: the two main triple targets in the zone (get glow + perfect flash)
// mirror: true = flip horizontally so left-right order feels natural to the player
var _dbKzZones = {
  // cx/cy: CX=W*cx, CY=W*cy.  rotDir: rotation = rotDir*π/2 - centerAngle
  // CX=W*cx (horizontal, W=canvas.width 4:3), CY=H*cy, R=H*r (H=canvas.height)
  // kz1: target at top (bull at bottom). cx:0.50 = center in wider 4:3 canvas
  // kz2: target at bottom (bull at top)
  kz1: { nums:[5,20,1,18,4],  scoring:[20,18], aboveNums:[12,5,20,1,18], szExtraNums:[9,4],
         kzAboveNums:[11,14,9,12,5,20,1,18,4,13,6],
         centerIdx:0,  mirror:false, cx:0.50, cy:0.81, rotDir:-1, r:0.55 },
  kz2: { nums:[7,19,3,17,2], scoring:[19,17], aboveNums:[7,19,3,17,2],  szExtraNums:[16,15],
         kzAboveNums:[6,10,15,2,17,3,19,7,16,8,11],
         centerIdx:10, mirror:false, cx:0.50, cy:0.19, rotDir: 1, r:0.55 }
};

// Restore persisted mode
try { var _km = localStorage.getItem('db_kz_mode'); if (_dbKzZones[_km]) _dbKzMode = _km; } catch(e) {}
try { var _um = localStorage.getItem('db_ui_mode'); if (_um === 'grid' || _um === 'scr') _dbUIMode = _um; } catch(e) {}
try { _dbAutoChange = localStorage.getItem('db_auto_change') === '1'; } catch(e) {}

// Visual ring boundaries shared by draw + hit test (single source of truth)
var _kzTriI = 0.520, _kzTriO = 0.614, _kzDblI = 0.906;
// SZ-mode overrides: triple ring closer to center for easier tap input
var _szTriI = 0.410, _szTriO = 0.510;

function _dbSetUIMode(mode) {
  _dbUIMode = mode;
  try { localStorage.setItem('db_ui_mode', mode); } catch(e) {}
  var gridBtn  = document.getElementById('db-mode-grid');
  var boardBtn = document.getElementById('db-mode-board');
  var kzBtn    = document.getElementById('db-mode-kz');
  var scrBtn   = document.getElementById('db-mode-scr');
  var kzTabs   = document.getElementById('db-kz-tabs');
  var gridWrap = document.getElementById('db-grid-wrap');
  var scrWrap  = document.getElementById('db-scr-wrap');
  var cvWrap   = document.getElementById('db-canvas-wrap');
  if (gridBtn)  gridBtn.classList.toggle('db-mode-on',  mode === 'grid');
  if (boardBtn) boardBtn.classList.toggle('db-mode-on', mode === 'board');
  if (kzBtn)    kzBtn.classList.toggle('db-mode-on',    mode === 'kz');
  if (scrBtn)   scrBtn.classList.toggle('db-mode-on',   mode === 'scr');
  if (kzTabs)   kzTabs.style.display   = (mode === 'kz') ? 'flex' : 'none';
  var isGrid = (mode === 'grid');
  var isScr  = (mode === 'scr');
  if (gridWrap) gridWrap.style.display = isGrid ? 'flex' : 'none';
  if (scrWrap)  scrWrap.style.display  = isScr  ? 'flex' : 'none';
  if (cvWrap)   cvWrap.style.display   = (isGrid || isScr) ? 'none' : '';
  // グリッド/SCR は各入力内にMissあり → アクション行のMissボタン非表示
  var missBtn = document.getElementById('db-miss-btn');
  if (missBtn) missBtn.style.display = (isGrid || isScr) ? 'none' : '';
  if (!isGrid && !isScr) _dbRedraw();
}

function _dbKzSetMode(m) {
  _dbKzMode = m;
  try { localStorage.setItem('db_kz_mode', m); } catch(e) {}
  // Only toggle tabs that have data-mode — excludes the 自動 button
  document.querySelectorAll('.db-kz-tab[data-mode]').forEach(function(t) {
    t.classList.toggle('db-kz-tab-on', t.dataset.mode === m);
  });
  _dbSyncAutoBtn();  // restore auto button to its true on/off state
  _dbRedraw();  // markers hidden per-zone via _kzZone tag in _dbDrawMarkers
}

function _dbToggleAutoChange() {
  _dbAutoChange = !_dbAutoChange;
  try { localStorage.setItem('db_auto_change', _dbAutoChange ? '1' : '0'); } catch(e) {}
  var btn = document.getElementById('db-kz-auto');
  if (btn) btn.classList.toggle('db-auto-on', _dbAutoChange);
}

function _dbSyncAutoBtn() {
  var btn = document.getElementById('db-kz-auto');
  if (btn) btn.classList.toggle('db-auto-on', _dbAutoChange);
}

// ── SCR zone grid ───────────────────────────────────────────
var _dbScrZone = 'kz1';  // 'kz1'=T20エリア 'kz2'=T19エリア

function _dbScrSetZone(zone) {
  _dbScrZone = zone;
  document.querySelectorAll('.db-scr-zone-btn').forEach(function(btn) {
    btn.classList.toggle('db-scr-zone-on', btn.dataset.zone === zone);
  });
  var g1 = document.getElementById('db-scr-kz1');
  var g2 = document.getElementById('db-scr-kz2');
  if (g1) g1.style.display = (zone === 'kz1') ? 'grid' : 'none';
  if (g2) g2.style.display = (zone === 'kz2') ? 'grid' : 'none';
}

// ── SCR Stats Recording ─────────────────────────────────────
var _SCR_STATS_KEY = 'db_scr_stats';

function _dbScrGetStats() {
  try { return JSON.parse(localStorage.getItem(_SCR_STATS_KEY) || '{}'); } catch(e) { return {}; }
}

function _dbScrRecord(zone, label, score) {
  var today = new Date().toISOString().slice(0, 10);
  var s = _dbScrGetStats();
  if (!s.kz1) s.kz1 = { total: 0, scoreSum: 0 };
  if (!s.kz2) s.kz2 = { total: 0, scoreSum: 0 };
  if (s.today !== today) {
    s.today = today;
    s.todayKz1 = { total: 0, scoreSum: 0 };
    s.todayKz2 = { total: 0, scoreSum: 0 };
  }
  if (!s.todayKz1) s.todayKz1 = { total: 0, scoreSum: 0 };
  if (!s.todayKz2) s.todayKz2 = { total: 0, scoreSum: 0 };
  // All-time
  s[zone].total = (s[zone].total || 0) + 1;
  s[zone].scoreSum = (s[zone].scoreSum || 0) + score;
  s[zone][label] = (s[zone][label] || 0) + 1;
  // Today
  var tk = zone === 'kz1' ? 'todayKz1' : 'todayKz2';
  s[tk].total = (s[tk].total || 0) + 1;
  s[tk].scoreSum = (s[tk].scoreSum || 0) + score;
  s[tk][label] = (s[tk][label] || 0) + 1;
  try { localStorage.setItem(_SCR_STATS_KEY, JSON.stringify(s)); } catch(e) {}
}

function _dbScrTap(score, label) {
  if (_db.darts.length >= 3) return;
  _dbScrRecord(_dbScrZone, label, score);
  _dbAddDart({ score: score, label: label });
}

// ── Grid input ──────────────────────────────────────────────
var _dbGridMult = 1;  // 1=Single 2=Double 3=Triple

function _dbGridSetMult(m) {
  _dbGridMult = m;
  document.querySelectorAll('.db-grid-mult-btn').forEach(function(btn) {
    btn.classList.toggle('db-grid-mult-on', parseInt(btn.dataset.mult) === m);
  });
}

function _dbGridTapNum(num) {
  if (_db.darts.length >= 3) return;
  var m = _dbGridMult;
  var label = m === 3 ? 'T' + num : m === 2 ? 'D' + num : String(num);
  _dbAddDart({ score: num * m, label: label });
}

function _dbGridTapSpec(score, label) {
  if (_db.darts.length >= 3) return;
  _dbAddDart({ score: score, label: label });
}

function _dbDrawKezuri() {
  var canvas = _db.canvas;
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  var W   = canvas.width;

  var H = canvas.height;
  var zone    = _dbKzZones[_dbKzMode];
  var primary = zone.nums;
  var idx     = zone.centerIdx;
  // kz1: target at top (bull at bottom), kz2: target at bottom (bull at top)
  // CX uses W (4:3 width), CY/R use H (height = square baseline)
  var R  = H * zone.r;
  var CX = W * zone.cx;
  var CY = H * zone.cy;
  var wire = Math.max(2, H / 250);

  // Visual ring boundaries — shared with hit test via _kzTriI/_kzTriO/_kzDblI
  var kzTriI = _kzTriI, kzTriO = _kzTriO, kzDblI = _kzDblI;

  ctx.clearRect(0, 0, W, H);
  ctx.fillStyle = DB_C.bg;
  ctx.fillRect(0, 0, W, H);

  var centerAngle = DB_START + idx * DB_SEG + DB_SEG / 2;
  var rotation    = zone.rotDir * Math.PI / 2 - centerAngle;
  var mirrorX     = zone.mirror ? -1 : 1;

  var MC = { seg1:'#0f0f0d', seg2:'#141412', tri:'#111110' };

  ctx.save();
  ctx.translate(CX, CY);
  ctx.rotate(rotation);
  if (zone.mirror) ctx.scale(-1, 1);
  ctx.translate(-CX, -CY);

  // Outer ring border
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.dbl * R + wire * 3, 0, Math.PI * 2);
  ctx.fillStyle = '#3a3420';
  ctx.fill();

  // Segments — all full color
  for (var i = 0; i < 20; i++) {
    var a1  = DB_START + i * DB_SEG;
    var a2  = a1 + DB_SEG;
    var odd = (i % 2 === 0);
    _dbArc(ctx,CX,CY, DB_R.obull*R, kzTriI*R,  a1,a2, odd?DB_C.black:DB_C.cream);
    _dbArc(ctx,CX,CY, kzTriI*R,     kzTriO*R,  a1,a2, odd?DB_C.red  :DB_C.green);
    _dbArc(ctx,CX,CY, kzTriO*R,     kzDblI*R,  a1,a2, odd?DB_C.black:DB_C.cream);
    _dbArc(ctx,CX,CY, kzDblI*R,     DB_R.dbl*R,a1,a2, odd?DB_C.red  :DB_C.green);
  }

  // (glow removed)

  // Radial wires
  for (var k = 0; k < 20; k++) {
    ctx.strokeStyle = DB_C.wire;
    ctx.lineWidth   = wire;
    var wa = DB_START + k * DB_SEG;
    ctx.beginPath();
    ctx.moveTo(CX+Math.cos(wa)*DB_R.obull*R, CY+Math.sin(wa)*DB_R.obull*R);
    ctx.lineTo(CX+Math.cos(wa)*DB_R.dbl*R,   CY+Math.sin(wa)*DB_R.dbl*R);
    ctx.stroke();
  }

  // Ring wires
  [kzTriI,kzTriO,kzDblI,DB_R.dbl].forEach(function(r){
    ctx.beginPath();
    ctx.arc(CX, CY, r*R, 0, Math.PI*2);
    ctx.strokeStyle = DB_C.wire;
    ctx.lineWidth   = wire * 0.8;
    ctx.stroke();
  });

  // Bull — enabled (barely visible at very bottom)
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.obull*R, 0, Math.PI*2);
  ctx.fillStyle = DB_C.obull; ctx.fill();
  ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire; ctx.stroke();
  ctx.beginPath();
  ctx.arc(CX, CY, DB_R.bull*R, 0, Math.PI*2);
  ctx.fillStyle = DB_C.bull; ctx.fill();

  ctx.restore();  // end rotation+mirror — text is now drawn upright

  // Labels — all visible segments
  var numR       = DB_R.dbl * R + wire * 5 + R * 0.075;
  var outerSinR  = (kzTriO + kzDblI) / 2 * R;
  var triMidR    = (kzTriI + kzTriO) / 2 * R;
  var outline    = Math.max(2, R * 0.008);
  var fmg        = Math.floor(R * 0.07);
  ctx.textAlign    = 'center';
  ctx.textBaseline = 'middle';

  for (var j = 0; j < 20; j++) {
    var jnum = DB_NUMS[j];
    var ca = DB_START + j * DB_SEG + DB_SEG / 2 + rotation;
    // Check if triple center is within canvas (segment is visible)
    var tx = CX + mirrorX * Math.cos(ca) * triMidR;
    var ty = CY + Math.sin(ca) * triMidR;
    if (tx < -R * 0.1 || tx > W + R * 0.1 || ty < -R * 0.1 || ty > H + R * 0.1) continue;

    var isScoring = zone.scoring.indexOf(jnum) >= 0;
    var isPri     = primary.indexOf(jnum) >= 0;
    var kzAbove   = zone.kzAboveNums || zone.aboveNums;
    var isAbove   = kzAbove.indexOf(jnum) >= 0;

    var jx, jy;
    if (isAbove) {
      // Above-ring numbers: outside double ring, clamp to canvas edges
      jx = CX + mirrorX * Math.cos(ca) * numR;
      jy = CY + Math.sin(ca) * numR;
      jx = Math.max(fmg, Math.min(W - fmg, jx));
      jy = Math.max(fmg, Math.min(H - fmg, jy));
    } else {
      // Outer-edge numbers: in the outer single area
      jx = CX + mirrorX * Math.cos(ca) * outerSinR;
      jy = CY + Math.sin(ca) * outerSinR;
      if (jx < fmg || jx > W - fmg || jy < fmg || jy > H - fmg) continue;
    }
    if (isScoring) {
      ctx.font        = 'bold ' + Math.floor(R * 0.155) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.75)';
      ctx.lineWidth   = Math.max(3, R * 0.013);
      ctx.strokeText(String(jnum), jx, jy);
      ctx.fillStyle   = DB_C.num;
      ctx.fillText(String(jnum), jx, jy);
    } else if (isAbove) {
      // Above-ring non-scoring (e.g. 12,5,1 for kz1)
      ctx.font        = 'bold ' + Math.floor(R * 0.11) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.65)';
      ctx.lineWidth   = outline;
      ctx.strokeText(String(jnum), jx, jy);
      ctx.fillStyle   = 'rgba(232,255,71,0.75)';
      ctx.fillText(String(jnum), jx, jy);
    } else {
      // Outer-single numbers
      ctx.font        = 'bold ' + Math.floor(R * 0.09) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.5)';
      ctx.lineWidth   = outline;
      ctx.strokeText(String(jnum), jx, jy);
      ctx.fillStyle   = 'rgba(232,255,71,0.55)';
      ctx.fillText(String(jnum), jx, jy);
    }
  }
  ctx.shadowBlur = 0;
}

// Hit test for kezuri zoomed view (reverses the rotation transform)
function _dbHitTestKezuri(tapX, tapY) {
  var canvas = _db.canvas;
  var rect   = canvas.getBoundingClientRect();
  var scaleX = canvas.width  / rect.width;
  var scaleY = canvas.height / rect.height;
  var cx     = (tapX - rect.left) * scaleX;
  var cy     = (tapY - rect.top)  * scaleY;

  var W  = canvas.width;
  var H  = canvas.height;
  var zone     = _dbKzZones[_dbKzMode];
  var R  = H * zone.r;
  var CX = W * zone.cx;
  var CY = H * zone.cy;

  var idx      = zone.centerIdx;
  var centerAngle = DB_START + idx * DB_SEG + DB_SEG / 2;
  var rotation    = zone.rotDir * Math.PI / 2 - centerAngle;

  // Un-mirror for kz2 before reversing rotation
  if (zone.mirror) cx = W - cx;

  // Reverse rotation
  var dx  = cx - CX, dy = cy - CY;
  var rdx = dx * Math.cos(-rotation) - dy * Math.sin(-rotation);
  var rdy = dx * Math.sin(-rotation) + dy * Math.cos(-rotation);

  var r  = Math.sqrt(rdx*rdx + rdy*rdy);
  var rn = r / R;

  if (rn > DB_R.dbl)   return { score:0,  label:'Miss' };
  if (rn < DB_R.bull)  return { score:50, label:'Bull' };
  if (rn < DB_R.obull) return { score:25, label:'25'   };

  var angle  = Math.atan2(rdy, rdx) * 180 / Math.PI + 90;
  if (angle < 0) angle += 360;
  var segIdx = Math.floor(((angle + 9) % 360) / 18) % 20;
  var num    = DB_NUMS[segIdx];

  if (rn < _kzTriI)   return { score:num,   label:String(num) };
  if (rn < _kzTriO)   return { score:num*3, label:'T'+num    };
  if (rn < _kzDblI)   return { score:num,   label:String(num) };
  return                     { score:num*2,  label:'D'+num    };
}

// ============================================================
// OPEN / CLOSE
// ============================================================

function dbOpen(mode) {
  _db.darts = [];
  _db.mode  = mode || 'cu';
  var modal = document.getElementById('db-modal');
  if (!modal) return;

  // CountUp: show board inline inside #isec instead of full-screen modal
  var isec  = (mode === 'cu') ? document.getElementById('isec') : null;
  var inner = modal.querySelector('.db-modal-inner');
  if (isec && inner) {
    // Hide normal isec children
    Array.from(isec.children).forEach(function(c) { c.dataset.dbHide = '1'; c.style.display = 'none'; });
    isec.appendChild(inner);
    isec.classList.add('db-isec-active');
    _dbIsInline = true;
    _dbCuPersist = true;  // remember user chose board input
  } else {
    modal.classList.add('db-show');
    modal.classList.toggle('db-01-mode', mode === '01');
    _dbIsInline = false;
  }

  _db.open = true;
  _dbUpdateDisplay();
  // Sync all UI mode state via _dbSetUIMode (handles grid/canvas visibility too)
  _dbSetUIMode(_dbUIMode);
  // Sync persisted kezuri mode tab
  document.querySelectorAll('.db-kz-tab[data-mode]').forEach(function(t) {
    t.classList.toggle('db-kz-tab-on', t.dataset.mode === _dbKzMode);
  });
  _dbSyncAutoBtn();
}

function dbClose() {
  var modal = document.getElementById('db-modal');
  if (_dbIsInline) {
    var isec  = document.getElementById('isec');
    var inner = isec && isec.querySelector('.db-modal-inner');
    if (inner && modal) {
      modal.appendChild(inner);
      isec.classList.remove('db-isec-active');
      Array.from(isec.children).forEach(function(c) {
        if (c.dataset.dbHide) { c.style.display = ''; delete c.dataset.dbHide; }
      });
    }
    _dbIsInline = false;
  }
  if (modal) modal.classList.remove('db-show');
  _db.open = false;
}

// ============================================================
// FLASH INDICATOR
// ============================================================

function _dbFlash(hit) {
  var el = document.getElementById('db-flash');
  if (!el) return;
  el.textContent = hit.score === 0 ? 'Miss!' : hit.label + '  +' + hit.score;
  var cls = 'db-flash db-flash-show';

  // Kezuri/SZ mode: color-code flash by hit quality
  if (_dbUIMode === 'kz' || _dbUIMode === 'sz') {
    var zone = _dbUIMode === 'sz'
      ? (_dbKzZones[hit._szSection === 'top' ? 'kz1' : 'kz2'] || null)
      : _dbKzZones[_dbKzMode];
  if (zone) {
    var m      = hit.label.match(/^[TD]?(\d+)$/);
    var hitNum = m ? parseInt(m[1]) : 0;
    var isTriple = hit.label.charAt(0) === 'T';

    if (isTriple && zone.scoring.indexOf(hitNum) >= 0) {
      cls += ' db-flash-perfect';            // scoring triple — green glow
    } else if (zone.nums.indexOf(hitNum) >= 0) {
      cls += ' db-flash-good';               // in zone (single/double) — light green
    } else if (hit.score === 0) {
      cls += ' db-flash-miss';               // miss — red
    } else {
      cls += ' db-flash-off';                // off-target number — amber
    }
  } }

  el.className = cls;
  setTimeout(function() { el.className = 'db-flash'; }, 1500);
}

// ============================================================
// TOUCH / CLICK HANDLER
// ============================================================

function _dbOnTap(e) {
  e.preventDefault();
  if (_db.darts.length >= 3) return;
  var touch = e.changedTouches ? e.changedTouches[0] : e;
  var hit = _dbUIMode === 'kz' ? _dbHitTestKezuri(touch.clientX, touch.clientY)
          : _dbUIMode === 'sz' ? _dbHitTestSZ(touch.clientX, touch.clientY)
          : _dbHitTest(touch.clientX, touch.clientY);
  hit._tapX = touch.clientX;
  hit._tapY = touch.clientY;
  hit._uiMode = _dbUIMode;
  if (_dbUIMode === 'kz') hit._kzZone = _dbKzMode;
  _dbAddDart(hit);
}

// ============================================================
// INIT
// ============================================================

window.addEventListener('load', function() {
  var canvas = document.getElementById('db-canvas');
  if (!canvas) return;
  _db.canvas = canvas;

  // Retina-aware sizing
  var dpr  = window.devicePixelRatio || 1;
  var size = Math.min(window.innerWidth - 16, 440);
  _dbDPR      = dpr;
  _dbInitSize = size;
  canvas.style.width  = size + 'px';
  canvas.style.height = size + 'px';
  canvas.width  = size * dpr;
  canvas.height = size * dpr;

  canvas.addEventListener('touchstart', _dbOnTap, { passive: false });
  canvas.addEventListener('click',      _dbOnTap);

  dbDraw();
});

// ============================================================
// SCORING MODE — variable-width sector board
// Higher-scoring numbers (T20, T19) have wider sectors for easier tap input
// ============================================================

var _szVB = null;  // precomputed {order, starts, angles}

function _szVBInit() {
  if (_szVB) return;
  var order = [20,1,18,4,13,6,10,15,2,17,3,19,7,16,8,11,14,9,12,5];
  var freq  = {20:10,1:4,5:4,19:9,3:3,7:3,18:2,17:2,12:1.5,14:1.5,
               15:1,2:1,9:1,10:1,4:0.7,13:0.7,16:0.5,8:0.5,11:0.5,6:0.5};
  var minA = 9, maxA = 28;
  var fv   = order.map(function(n) { return freq[n]; });
  var fMin = Math.min.apply(null, fv);
  var fMax = Math.max.apply(null, fv);
  var raw  = fv.map(function(f) {
    var t = (f - fMin) / (fMax - fMin);
    return minA + (maxA - minA) * Math.pow(t, 0.8);
  });
  var rawSum = raw.reduce(function(a, b) { return a + b; }, 0);
  var angles = raw.map(function(a) { return a * 360 / rawSum; });
  var starts = [], cum = -90 - angles[0] / 2;
  for (var i = 0; i < 20; i++) { starts.push(cum); cum += angles[i]; }
  _szVB = { order: order, starts: starts, angles: angles };
}

function _dbDrawSZ() {
  _szVBInit();
  var canvas = _db.canvas;
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  var W   = canvas.width;
  var cx  = W / 2, cy = W / 2;
  // Scale so board (r=190) + numbers (r=210) fit with ~4% margin
  var scale = (W / 2) / 220;

  var rBullseye = 22  * scale;
  var rBull     = 48  * scale;
  var rTriI     = 68  * scale;
  var rTriO     = 103 * scale;
  var rDblI     = 175 * scale;
  var rDblO     = 190 * scale;
  var rBoard    = 190 * scale;
  var wire      = '#999';
  var lw        = Math.max(0.5, scale * 0.5);

  // Clear
  ctx.fillStyle = DB_C.bg;
  ctx.fillRect(0, 0, W, W);

  // Outer black rim
  ctx.beginPath();
  ctx.arc(cx, cy, rBoard + 12 * scale, 0, Math.PI * 2);
  ctx.fillStyle = '#222';
  ctx.fill();

  function sectorColor(i, isD, isT) {
    var ev = i % 2 === 0;
    if (isD || isT) return ev ? '#c0392b' : '#27ae60';
    return ev ? '#1a1a1a' : '#c8b888';
  }

  function drawSec(s, e, ri, ro, col) {
    var sr = s * Math.PI / 180, er = e * Math.PI / 180;
    ctx.beginPath();
    ctx.arc(cx, cy, ro, sr, er);
    ctx.arc(cx, cy, ri, er, sr, true);
    ctx.closePath();
    ctx.fillStyle = col;
    ctx.fill();
    ctx.strokeStyle = wire;
    ctx.lineWidth = lw;
    ctx.stroke();
  }

  var vb = _szVB;
  for (var i = 0; i < 20; i++) {
    var s = vb.starts[i], e = s + vb.angles[i];
    drawSec(s, e, rBull, rTriI, sectorColor(i, false, false));
    drawSec(s, e, rTriI, rTriO, sectorColor(i, false, true));
    drawSec(s, e, rTriO, rDblI, sectorColor(i, false, false));
    drawSec(s, e, rDblI, rDblO, sectorColor(i, true,  false));
  }

  // 25 ring (bull)
  ctx.beginPath(); ctx.arc(cx, cy, rBull, 0, Math.PI * 2);
  ctx.fillStyle = '#27ae60'; ctx.fill();
  ctx.strokeStyle = wire; ctx.lineWidth = lw; ctx.stroke();

  // Bullseye
  ctx.beginPath(); ctx.arc(cx, cy, rBullseye, 0, Math.PI * 2);
  ctx.fillStyle = '#c0392b'; ctx.fill();
  ctx.strokeStyle = wire; ctx.lineWidth = lw; ctx.stroke();

  // Radial wires
  for (var i = 0; i < 20; i++) {
    var rad = vb.starts[i] * Math.PI / 180;
    ctx.beginPath();
    ctx.moveTo(cx + rBull  * Math.cos(rad), cy + rBull  * Math.sin(rad));
    ctx.lineTo(cx + rBoard * Math.cos(rad), cy + rBoard * Math.sin(rad));
    ctx.strokeStyle = wire; ctx.lineWidth = Math.max(0.8, scale * 0.8); ctx.stroke();
  }

  // Numbers
  var fSize = Math.max(9, Math.round(13 * scale));
  ctx.font = '600 ' + fSize + 'px sans-serif';
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  for (var i = 0; i < 20; i++) {
    var mid = (vb.starts[i] + vb.angles[i] / 2) * Math.PI / 180;
    var nr  = rBoard + 20 * scale;
    ctx.fillStyle = '#ddd';
    ctx.fillText(String(vb.order[i]), cx + nr * Math.cos(mid), cy + nr * Math.sin(mid));
  }
  _szLayout = null;
}

// Draw one strip using kz zone geometry
function _dbDrawSZStrip(ctx, W, R, CY, zone, wireYTop, wireYBot, Wpad) {
  Wpad = Wpad || 0;
  var _kzTriI = _szTriI, _kzTriO = _szTriO;  // SZ uses closer-to-center ring radii
  var CX   = W / 2;
  var wire = Math.max(2, R * 0.003);
  var idx  = zone.centerIdx;
  var centerAngle = DB_START + idx * DB_SEG + DB_SEG / 2;
  var rotation    = zone.rotDir * Math.PI / 2 - centerAngle;

  var szInI  = DB_R.obull + (_kzTriI - DB_R.obull) * 0.75;
  var szOutO = _kzTriO    + (_kzDblI  - _kzTriO)   * 0.5;
  var szDblO = szOutO     + (_kzTriO  - _kzTriI)    * 2 / 3;   // double ring: 2/3 of triple width

  // Phase 1: full board color layout extending to bullCY (no clip).
  // Draws inner single + triple + outer single + double with proper colors.
  ctx.save();
  ctx.translate(CX, CY); ctx.rotate(rotation); ctx.translate(-CX, -CY);
  ctx.beginPath();
  ctx.arc(CX, CY, szDblO * R + wire * 3, 0, Math.PI * 2);
  ctx.fillStyle = '#3a3420'; ctx.fill();
  for (var i = 0; i < 20; i++) {
    var a1 = DB_START + i * DB_SEG, a2 = a1 + DB_SEG, odd = (i % 2 === 0);
    _dbArc(ctx, CX, CY, DB_R.obull*R, _kzTriI*R, a1, a2, odd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, _kzTriI*R,    _kzTriO*R, a1, a2, odd ? DB_C.red   : DB_C.green);
    _dbArc(ctx, CX, CY, _kzTriO*R,    szOutO*R,  a1, a2, odd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, szOutO*R,     szDblO*R,  a1, a2, odd ? DB_C.red   : DB_C.green);
  }
  ctx.restore();

  // Phase 2: inner single + scoring zone + highlights + wires
  // clipped to ORIGINAL strip area — keeps bright colors in the strip only.
  ctx.save();
  if (wireYTop !== undefined && wireYBot !== undefined) {
    ctx.beginPath(); ctx.rect(0, wireYTop, W, wireYBot - wireYTop); ctx.clip();
  }
  ctx.save();
  ctx.translate(CX, CY); ctx.rotate(rotation); ctx.translate(-CX, -CY);
  for (var j = 0; j < 20; j++) {
    var ja1 = DB_START + j * DB_SEG, ja2 = ja1 + DB_SEG, jodd = (j % 2 === 0);
    _dbArc(ctx, CX, CY, DB_R.obull*R, szInI*R,  ja1, ja2, jodd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, szInI*R,      _kzTriI*R, ja1, ja2, jodd ? DB_C.black : DB_C.cream);
    _dbArc(ctx, CX, CY, _kzTriI*R,    _kzTriO*R, ja1, ja2, jodd ? DB_C.red   : DB_C.green);
    _dbArc(ctx, CX, CY, szOutO*R,     szDblO*R,  ja1, ja2, jodd ? DB_C.red   : DB_C.green);
  }
  ctx.restore(); // end rotation (inside strip clip)
  ctx.restore(); // end strip clip

  // Scoring glow drawn OUTSIDE strip clip so the full triple border is visible
  // (prevents clipping at wireYBot for segments near the strip edge like T18).
  ctx.save();
  ctx.translate(CX, CY); ctx.rotate(rotation); ctx.translate(-CX, -CY);
  zone.scoring.forEach(function(sNum) {
    var si = DB_NUMS.indexOf(sNum);
    var sa1 = DB_START + si * DB_SEG, sa2 = sa1 + DB_SEG;
    ctx.save();
    ctx.shadowColor = 'rgba(232,255,71,0.55)'; ctx.shadowBlur = R * 0.04;
    ctx.beginPath();
    ctx.arc(CX, CY, _kzTriO * R, sa1, sa2);
    ctx.arc(CX, CY, _kzTriI * R, sa2, sa1, true);
    ctx.closePath();
    ctx.strokeStyle = 'rgba(232,255,71,0.5)';
    ctx.lineWidth   = Math.max(3, R * 0.012);
    ctx.stroke(); ctx.restore();
  });
  // Re-draw ring wires on top of glow so borders stay crisp.
  [_kzTriI, _kzTriO, szOutO, szDblO].forEach(function(r) {
    ctx.beginPath(); ctx.arc(CX, CY, r * R, 0, Math.PI * 2);
    ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire; ctx.stroke();
  });
  ctx.restore(); // end glow rotation

  // Wires drawn outside clip — covers Phase 1 gap area (Hs..bullCY) too,
  // giving clean segment boundaries across the full visible board.
  for (var k = 0; k < 20; k++) {
    var wa = DB_START + k * DB_SEG + rotation;
    ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire;
    ctx.beginPath();
    ctx.moveTo(CX + Math.cos(wa) * DB_R.obull * R, CY + Math.sin(wa) * DB_R.obull * R);
    ctx.lineTo(CX + Math.cos(wa) * szDblO   * R, CY + Math.sin(wa) * szDblO   * R);
    ctx.stroke();
  }
  [_kzTriI, _kzTriO, szOutO, szDblO].forEach(function(r) {
    ctx.beginPath(); ctx.arc(CX, CY, r * R, 0, Math.PI * 2);
    ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire * 0.8; ctx.stroke();
  });

  var szOutO2 = _kzTriO + (_kzDblI - _kzTriO) * 0.5;
  var numR      = (szOutO2 + 0.10) * R;
  var outerSinR = (_kzTriO + szOutO2) / 2 * R;
  var outline   = Math.max(2, R * 0.008);
  var fmg       = Math.floor(R * 0.03);
  var fmgV      = Math.round(R * 0.07);
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';

  for (var j = 0; j < 20; j++) {
    var jnum = DB_NUMS[j];
    var ca   = DB_START + j * DB_SEG + DB_SEG / 2 + rotation;
    var triX = CX + Math.cos(ca) * ((_kzTriI + _kzTriO) / 2 * R);
    if (triX < -R * 0.1 || triX > W + R * 0.1) continue;

    var isScoring = zone.scoring.indexOf(jnum) >= 0;
    var isAbove   = zone.aboveNums.indexOf(jnum) >= 0;
    var isSzExtra = zone.szExtraNums && zone.szExtraNums.indexOf(jnum) >= 0;
    var isSzVisible = isAbove || isSzExtra;
    var jx, jy;

    if (isSzVisible) {
      jx = CX + Math.cos(ca) * numR;
      jy = CY + Math.sin(ca) * numR;
      jx = Math.max(-Wpad + fmg, Math.min(W + Wpad - fmg, jx));
      jy = Math.max(fmgV, jy);
    } else {
      jx = CX + Math.cos(ca) * outerSinR;
      jy = CY + Math.sin(ca) * outerSinR;
      if (jx < fmg || jx > W - fmg) continue;
    }

    if (isScoring) {
      ctx.save();
      ctx.shadowColor = 'rgba(232,255,71,0.8)'; ctx.shadowBlur = R * 0.04;
      ctx.font = 'bold ' + Math.floor(R * 0.09) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.75)'; ctx.lineWidth = Math.max(3, R * 0.013);
      ctx.strokeText(String(jnum), jx, jy);
      ctx.fillStyle = DB_C.num; ctx.fillText(String(jnum), jx, jy);
      ctx.restore();
    } else if (isSzVisible) {
      ctx.font = 'bold ' + Math.floor(R * 0.09) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.65)'; ctx.lineWidth = outline;
      ctx.strokeText(String(jnum), jx, jy);
      ctx.fillStyle = DB_C.num; ctx.fillText(String(jnum), jx, jy);
    } else {
      ctx.font = Math.floor(R * 0.065) + 'px "Bebas Neue",Arial,sans-serif';
      ctx.fillStyle = 'rgba(240,224,160,0.45)'; ctx.fillText(String(jnum), jx, jy);
    }
  }
}

function _dbDrawSZBull(ctx, cx, cy, R) {
  var wire = Math.max(2, R * 0.015);
  // Subtle radial glow background behind bull
  var bgGrd = ctx.createRadialGradient(cx, cy, DB_R.bull * R, cx, cy, DB_R.obull * R * 2.5);
  bgGrd.addColorStop(0, 'rgba(58,52,32,0.25)');
  bgGrd.addColorStop(0.5, 'rgba(30,27,16,0.12)');
  bgGrd.addColorStop(1, 'rgba(15,14,8,0)');
  ctx.beginPath(); ctx.arc(cx, cy, DB_R.obull * R * 2.5, 0, Math.PI * 2);
  ctx.fillStyle = bgGrd; ctx.fill();
  // Outer bull
  ctx.beginPath(); ctx.arc(cx, cy, DB_R.obull * R, 0, Math.PI * 2);
  ctx.fillStyle = DB_C.obull; ctx.fill();
  ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire; ctx.stroke();
  // Inner bull
  ctx.beginPath(); ctx.arc(cx, cy, DB_R.bull * R, 0, Math.PI * 2);
  ctx.fillStyle = DB_C.bull; ctx.fill();
  ctx.strokeStyle = DB_C.wire; ctx.lineWidth = wire * 0.7; ctx.stroke();
  // Glow effect
  ctx.save();
  ctx.shadowColor = 'rgba(232,255,71,0.4)'; ctx.shadowBlur = R * 0.12;
  ctx.beginPath(); ctx.arc(cx, cy, DB_R.obull * R, 0, Math.PI * 2);
  ctx.strokeStyle = 'rgba(232,255,71,0.35)'; ctx.lineWidth = Math.max(2, R * 0.025);
  ctx.stroke(); ctx.restore();
}

function _dbHitTestSZ(tapX, tapY) {
  _szVBInit();
  var canvas = _db.canvas;
  if (!canvas) return { score:0, label:'Miss' };
  var rc = canvas.getBoundingClientRect();
  var px = (tapX - rc.left) * (canvas.width  / rc.width);
  var py = (tapY - rc.top)  * (canvas.height / rc.height);
  var W  = canvas.width;
  var scale = (W / 2) / 220;

  var rBullseye = 22  * scale;
  var rBull     = 48  * scale;
  var rTriI     = 68  * scale;
  var rTriO     = 103 * scale;
  var rDblI     = 175 * scale;
  var rDblO     = 190 * scale;

  var dx = px - W / 2, dy = py - W / 2;
  var r  = Math.sqrt(dx * dx + dy * dy);

  if (r < rBullseye) return { score:50, label:'Bull' };
  if (r < rBull)     return { score:25, label:'25'   };
  if (r > rDblO * 1.05) return { score:0, label:'Miss' };

  var vb    = _szVB;
  var angle = Math.atan2(dy, dx) * 180 / Math.PI;
  var s0    = vb.starts[0];
  var norm  = ((angle - s0) % 360 + 360) % 360;
  var cum = 0, sectorIdx = 19;
  for (var i = 0; i < 20; i++) {
    cum += vb.angles[i];
    if (norm < cum) { sectorIdx = i; break; }
  }
  var num = vb.order[sectorIdx];

  if (r < rTriI) return { score:num,     label:String(num) };
  if (r < rTriO) return { score:num * 3, label:'T' + num   };
  if (r < rDblI) return { score:num,     label:String(num) };
  if (r < rDblO) return { score:num * 2, label:'D' + num   };
  return { score:0, label:'Miss' };
}

function _dbHitTestSZStrip(cx, cy, W, R, CY, zone) {
  var _kzTriI = _szTriI, _kzTriO = _szTriO;  // SZ uses closer-to-center ring radii
  var CX  = W / 2;
  var idx = zone.centerIdx;
  var centerAngle = DB_START + idx * DB_SEG + DB_SEG / 2;
  var rotation    = zone.rotDir * Math.PI / 2 - centerAngle;

  var dx = cx - CX, dy = cy - CY;
  var cr = Math.cos(-rotation), sr = Math.sin(-rotation);
  var dxr = dx * cr - dy * sr, dyr = dx * sr + dy * cr;
  var rn  = Math.sqrt(dxr * dxr + dyr * dyr) / R;

  if (rn > DB_R.dbl + 0.15) return { score:0, label:'Miss' };
  if (rn < DB_R.bull)        return { score:50, label:'Bull' };
  if (rn < DB_R.obull)       return { score:25, label:'25'  };

  var angle  = Math.atan2(dyr, dxr) * 180 / Math.PI + 90;
  if (angle < 0) angle += 360;
  var segIdx = Math.floor(((angle + 9) % 360) / 18) % 20;
  var num    = DB_NUMS[segIdx];

  if (rn < _kzTriI) return { score:num,     label:String(num) };
  if (rn < _kzTriO) return { score:num * 3, label:'T' + num   };
  if (rn < _kzDblI) return { score:num,     label:String(num) };
  return               { score:num * 2, label:'D' + num   };
}
